	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)
func main() {
	ctx := context.Background()
	uri := "<connection-string>"
	client, err := mongo.Connect(options.Client().
		ApplyURI(uri))
	if err != nil {
		panic(err)
	}
	defer func() {
		if err := client.Disconnect(context.TODO()); err != nil {
			panic(err)
		}
	}()
	coll := client.Database("sample_analytics").Collection("customers")
	const indexName = "default"
	opts := options.SearchIndexes().SetName(indexName).SetType("search")
	// Define the MongoDB Search index for the boolean field
	searchIndexModel := mongo.SearchIndexModel{
		Definition: bson.D{
			{"mappings", bson.D{
				{"dynamic", false},
				{"fields", bson.D{
					{"active", bson.D{
						{"type", "boolean"},
					}},
				}},
			}},
		},
		Options: opts,
	}
	// Create the index
	searchIndexName, err := coll.SearchIndexes().CreateOne(ctx, searchIndexModel)
	if err != nil {
		log.Fatalf("Failed to create the Atlas Search index: %v", err)
	}
	fmt.Println("Name of index created: " + searchIndexName)
}

```

You can use the MongoDB Search `boolean` type to index `true` and `false`
values. You can query fields of type `boolean` using the [equals](equals-ref) and [in](in-ref) operators. You can also [sorting](sort-ref) by indexed `boolean` fields.

You can also use the `boolean` type to index:

- Fields whose value is an array of booleans. To learn more, see
  [How to Index the Elements of an Array](fts-array-ref).

- Boolean fields inside an array of documents indexed as the
  [embeddedDocuments](bson-data-types-embedded-documents) type.

If you enable [dynamic mappings](static-dynamic-mappings), MongoDB Search
automatically indexes fields of type dateFacet. You can
use the **Visual Editor** or the  **JSON Editor** in the Atlas UI to
index fields as the dateFacet type.

